     1→/**
     2→ * FolderSidebar Component
     3→ *
     4→ * Folder tree sidebar with search and tag filtering.
     5→ * Extracted from Notes.tsx as part of the Notes Page Revolution.
     6→ *
     7→ * Features:
     8→ * - Hierarchical folder tree with expand/collapse
     9→ * - Search notes with Cmd+K shortcut
    10→ * - Tag filtering with TagFilter component
    11→ * - Folder CRUD operations (create, rename, delete)
    12→ * - Resizable via parent container
    13→ */
    14→
    15→import React, { useEffect, useState, useRef, useMemo } from 'react';
    16→import { FolderOpen } from 'lucide-react';
    17→import { useFoldersStore } from '../../stores/useFoldersStore';
    18→import { useNotesStore } from '../../stores/useNotesStore';
    19→import { useUndoStore } from '../../stores/useUndoStore';
    20→import { ConfirmDialog } from '../ConfirmDialog';
    21→import { PromptDialog } from '../PromptDialog';
    22→import { TagFilter } from '../TagFilter';
    23→import { FolderTreeNode } from './FolderTreeNode';
    24→import { logger } from '../../services/logger';
    25→
    26→const log = logger.module('FolderSidebar');
    27→
    28→export interface FolderSidebarProps {
    29→  activeTags: string[];
    30→  onAddTag: (tag: string) => void;
    31→  onRemoveTag: (tag: string) => void;
    32→  onClearAllTags: () => void;
    33→  onOpenTagManager: () => void;
    34→}
    35→
    36→export const FolderSidebar: React.FC<FolderSidebarProps> = ({
    37→  activeTags,
    38→  onAddTag,
    39→  onRemoveTag,
    40→  onClearAllTags,
    41→  onOpenTagManager,
    42→}) => {
    43→  // Get raw folders object (stable reference unless folders change)
    44→  const foldersObj = useFoldersStore((state) => state.folders);
    45→  const activeFolderId = useFoldersStore((state) => state.activeFolderId);
    46→  const setActiveFolder = useFoldersStore((state) => state.setActiveFolder);
    47→  const createFolder = useFoldersStore((state) => state.createFolder);
    48→  const deleteFolder = useFoldersStore((state) => state.deleteFolder);
    49→  const updateFolder = useFoldersStore((state) => state.updateFolder);
    50→  const notesObj = useNotesStore((state) => state.notes);
    51→  const searchNotes = useNotesStore((state) => state.searchNotes);
    52→
    53→  // Dialog state
    54→  const [deleteDialogOpen, setDeleteDialogOpen] = useState(false);
    55→  const [renameDialogOpen, setRenameDialogOpen] = useState(false);
    56→  const [selectedFolderId, setSelectedFolderId] = useState<string | null>(null);
    57→  const [selectedFolderName, setSelectedFolderName] = useState('');
    58→
    59→  // Search state
    60→  const [searchQuery, setSearchQuery] = useState('');
    61→  const searchInputRef = useRef<HTMLInputElement>(null);
    62→
    63→  // Keyboard shortcut for search (Cmd+K)
    64→  useEffect(() => {
    65→    const handleKeyDown = (e: KeyboardEvent) => {
    66→      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
    67→        e.preventDefault();
    68→        searchInputRef.current?.focus();
    69→      }
    70→    };
    71→
    72→    window.addEventListener('keydown', handleKeyDown);
    73→    return () => window.removeEventListener('keydown', handleKeyDown);
    74→  }, []);
    75→
    76→  // Get tree structure for nested folders
    77→  const getTree = useFoldersStore((state) => state.getTree);
    78→  const toggleExpanded = useFoldersStore((state) => state.toggleExpanded);
    79→  const expandedFolderIds = useFoldersStore((state) => state.expandedFolderIds);
    80→
    81→  const folderTree = useMemo(() => getTree(), [foldersObj, getTree]);
    82→
    83→  // Get note count for a folder
    84→  const getFolderNoteCount = (folderId: string) => {
    85→    return Object.values(notesObj).filter((note) => note.folderId === folderId).length;
    86→  };
    87→
    88→  // Handle folder deletion
    89→  const handleDeleteFolder = (folderId: string, folderName: string) => {
    90→    setSelectedFolderId(folderId);
    91→    setSelectedFolderName(folderName);
    92→    setDeleteDialogOpen(true);
    93→  };
    94→
    95→  const confirmDeleteFolder = () => {
    96→    if (!selectedFolderId) return;
    97→
    98→    // Save folder and notes for undo
    99→    const folderToDelete = foldersObj[selectedFolderId];
   100→    if (!folderToDelete) {
   101→      log.warn('Folder not found', { folderId: selectedFolderId });
   102→      return;
   103→    }
   104→
   105→    const notesToDelete = Object.values(notesObj).filter(
   106→      (note) => note.folderId === selectedFolderId
   107→    );
   108→    const noteCount = notesToDelete.length;
   109→
   110→    // Delete all notes in this folder
   111→    notesToDelete.forEach((note) => {
   112→      useNotesStore.setState((state) => {
   113→        const { [note.id]: deleted, ...remainingNotes } = state.notes;
   114→        return {
   115→          notes: remainingNotes,
   116→          activeNoteId: state.activeNoteId === note.id ? null : state.activeNoteId,
   117→        };
   118→      });
   119→    });
   120→
   121→    // Delete the folder
   122→    deleteFolder(selectedFolderId);
   123→
   124→    log.info(`Folder "${folderToDelete.name}" deleted`, { noteCount });
   125→
   126→    // Add undo action to restore folder AND notes
   127→    useUndoStore.getState().addUndoAction(
   128→      `Folder "${folderToDelete.name}" and ${noteCount} note(s) deleted`,
   129→      () => {
   130→        // Restore the folder
   131→        useFoldersStore.setState((state) => ({
   132→          folders: {
   133→            ...state.folders,
   134→            [folderToDelete.id]: folderToDelete,
   135→          },
   136→        }));
   137→
   138→        // Restore all notes
   139→        useNotesStore.setState((state) => {
   140→          const restoredNotes = { ...state.notes };
   141→          notesToDelete.forEach((note) => {
   142→            restoredNotes[note.id] = note;
   143→          });
   144→          return {
   145→            notes: restoredNotes,
   146→          };
   147→        });
   148→
   149→        log.info(`Folder "${folderToDelete.name}" and ${noteCount} note(s) restored (undo)`);
   150→      }
   151→    );
   152→  };
   153→
   154→  // Handle folder rename
   155→  const handleRenameFolder = (folderId: string, currentName: string) => {
   156→    setSelectedFolderId(folderId);
   157→    setSelectedFolderName(currentName);
   158→    setRenameDialogOpen(true);
   159→  };
   160→
   161→  const confirmRenameFolder = (newName: string) => {
   162→    if (!selectedFolderId || !newName.trim()) return;
   163→    updateFolder(selectedFolderId, { name: newName.trim() });
   164→  };
   165→
   166→  return (
   167→    <div className="h-full p-5 flex flex-col overflow-hidden border-b border-border-light dark:border-border-dark">
